// Format each advisory into a clean Slack message object
const advisory = $input.item.json;

const severityEmoji = {
  critical: '🚨',
  high: '🔴',
  medium: '🟡',
  low: '🟢'
};

const emoji = severityEmoji[advisory.severity?.toLowerCase()] || '⚠️';

return {
  json: {
    severity: advisory.severity,
    title: advisory.summary || 'No title',
    cve_id: advisory.cve_id || 'N/A',
    url: advisory.html_url || '',
    published: advisory.published_at || 'Unknown',
    slack_message: {
      text: `${emoji} *Security Advisory Detected*`,
      blocks: [
        {
          type: 'header',
          text: {
            type: 'plain_text',
            text: `${emoji} ${advisory.severity?.toUpperCase()} Advisory`
          }
        },
        {
          type: 'section',
          fields: [
            { type: 'mrkdwn', text: `*Title:*\n${advisory.summary || 'N/A'}` },
            { type: 'mrkdwn', text: `*CVE ID:*\n${advisory.cve_id || 'N/A'}` },
            { type: 'mrkdwn', text: `*Severity:*\n${advisory.severity || 'N/A'}` },
            { type: 'mrkdwn', text: `*Published:*\n${advisory.published_at || 'N/A'}` }
          ]
        },
        {
          type: 'actions',
          elements: [
            {
              type: 'button',
              text: { type: 'plain_text', text: 'View Advisory' },
              url: advisory.html_url || 'https://github.com/advisories',
              style: 'danger'
            }
          ]
        }
      ]
    }
  }
};

// Log execution summary for audit trail
const now = new Date().toISOString();
const advisory = $input.item.json;

console.log(JSON.stringify({
  event: 'advisory_alert_sent',
  timestamp: now,
  severity: advisory.severity,
  cve_id: advisory.cve_id,
  status: 'success'
}));

return $input.item;
